vector<vector<int>> bcc_edge(int n, const vector<vector<int>>& g) {
	/**
	* 无向图边双连通分量：不包含桥的极大连通子图
	*
	* - 可能还要进一步用并查集缩点，然后建树
	*/

	vector<int> dfn(n + 1);   // dfs序时间戳
	vector<int> low(n + 1);   // 能回溯到的最早祖先的dfn
	vector<int> bcc_id(n + 1, 0); // 每个点所属的边双连通分量id
	stack<int> stk;
	vector<vector<int>> bccs; // 存储所有边双连通分量
	int time = 0;
	int bcc_cnt = 0;

	auto tarjan = [&](auto self, int u, int fa) -> void {
		dfn[u] = low[u] = ++time;
		stk.push(u);

		for (int v : g[u]) {
			if (v == fa) continue;

			if (!dfn[v]) {
				self(self, v, u);
				low[u] = min(low[u], low[v]);
			}
			else {
				// 环
				low[u] = min(low[u], dfn[v]);
			}
		}

		// 如果 u 是边双连通分量的根
		if (low[u] == dfn[u]) {
			bcc_cnt++;
			vector<int> bcc;
			while (true) {
				int top = stk.top();
				stk.pop();
				bcc_id[top] = bcc_cnt;
				bcc.push_back(top);
				if (top == u) break;
			}
			bccs.push_back(bcc);
		}
		};

	for (int i = 1; i <= n; i++) {
		if (!dfn[i]) {
			tarjan(tarjan, i, 0);
		}
	}
	return bccs;
}
