	int n, m; cin >> n >> m;
	var g = vector<vector<int>>(n + 1);
	var e = vector<pii>(m + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
		e[i] = { u,v };
	}
	var qu = vector<int>();
	int q; cin >> q;
	while (q--) {
		int x; cin >> x;
		qu.pb(x);
	}

	// 找边双连通分量，对双连通分量进行缩点
	var bccs = bcc_edge(n, g);
	int nn = bccs.size();
	var s = vector<int>(n + 1); // 原点 -> 缩点
	fa(i, 0, nn - 1) {
		for (int x : bccs[i])
			s[x] = i + 1;
	}

	// 在一个双连通分量内，没有必经之路，不满足题意
	if (s[1] == s[n]) {
		for (int q : qu)cout << -1 << ' ';
		cout << endl;
		return;
	}

	// 缩点建树
	var ng = vector<vector<pii>>(nn + 1); // 缩点后的树
	var mp = vector<int>(nn + 1);         // 缩点 -> 原点
	fa(i, 1, m) {
		const var& [u, v] = e[i];
		if (s[u] != s[v]) { // u -> v 是桥，u、v 是割点
			ng[s[u]].pb({ s[v],i });
			ng[s[v]].pb({ s[u],i });
			mp[s[u]] = u, mp[s[v]] = v;
		}
	}

	// 找 1 -> n 的必经边 
	var must = vector<int>();
	var dfs = [&](var dfs, int now, int fa)->bool {
		if (now == s[n])return 1;
		for (const var& [to, id] : ng[now]) {
			if (to == fa)continue;
			if (dfs(dfs, to, now)) {
				must.pb(id);
				return 1;
			}
		}
		return 0;
		};
	dfs(dfs, s[1], 0);

	// 多源最短路，找所有点到割点的最短距离
	var dis = vector<pii>(n + 1, { INF, INF });
	var Q = queue<pii>();
	sort(all(must)); // 按边 id 排序
	for (int id : must) {
		const var& [x, y] = e[id];
		if (dis[x].px)Q.push({ x,0 }), dis[x] = { 0,id };
		if (dis[y].px)Q.push({ y,0 }), dis[y] = { 0,id };
	}
	while (Q.size()) {
		var[now, d] = Q.front();
		Q.pop();
		if (d > dis[now].px)continue;
		for (int to : g[now]) {
			if (dis[to].px > dis[now].px + 1) {
				dis[to].px = dis[now].px + 1;
				dis[to].py = dis[now].py;
				Q.push({ to,dis[to].px });
			}
			else if (dis[to].px == dis[now].px + 1) {
				dis[to].py = min(dis[now].py, dis[to].py);
			}
		}
	}

	for (int x : qu)cout << dis[x].py << ' ';
	cout << endl;
	return;
}
